import { useState, useEffect } from "react";
import { useSelector, useDispatch } from "react-redux";
import { useNavigate, useParams } from "react-router-dom";
import { logout } from "../authReducer";

function EditCourse() {
  const { id } = useParams();
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const user = useSelector((state) => state.auth.user);
  const [name, setName] = useState("");
  const [description, setDescription] = useState("");
  const [course, setCourse] = useState(null);

  useEffect(() => {
    if (!user) {
      navigate("/login");
      return;
    }

    fetch(`http://localhost:3001/courses/${id}`)
      .then((res) => res.json())
      .then((data) => {
        if (user.role !== "admin" && (user.role !== "teacher" || data.teacherId !== user.id)) {
          alert("Access denied! You can only edit your own courses or be an admin.");
          dispatch(logout());
          navigate("/login");
        } else {
          setCourse(data);
          setName(data.name);
          setDescription(data.description);
        }
      })
      .catch((error) => {
        console.error("Error fetching course:", error);
        alert("Failed to load course");
      });
  }, [id, user, dispatch, navigate]);

  async function handleSubmit(e) {
    e.preventDefault();
    const updatedCourse = { ...course, name, description };

    const response = await fetch(`http://localhost:3001/courses/${id}`, {
      method: "PUT",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(updatedCourse),
    });

    if (response.ok) {
      alert("Course updated successfully!");
      navigate("/courses");
    } else {
      alert("Failed to update course.");
    }
  }

  if (!course) return <div className="page-container">Loading...</div>;

  return (
    <div className="page-container">
      <div className="form-container">
        <h1>Edit Course</h1>
        <form onSubmit={handleSubmit}>
          <input
            type="text"
            placeholder="Course Name"
            value={name}
            onChange={(e) => setName(e.target.value)}
            required
          />
          <input
            type="text"
            placeholder="Description"
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            required
          />
          <button type="submit">Update Course</button>
        </form>
      </div>
    </div>
  );
}

export default EditCourse;
